import { BookOpen } from "lucide-react";

interface Term {
  term: string;
  definition: string;
}

interface GlossarySectionProps {
  terms: Term[];
  headingLevel?: "h2" | "h3";
}

export default function GlossarySection({ terms, headingLevel = "h2" }: GlossarySectionProps) {
  const Heading = headingLevel;

  return (
    <section className="mt-8">
      <Heading className="text-lg font-bold text-foreground mb-4 flex items-center gap-2">
        <BookOpen className="w-4 h-4 text-primary flex-shrink-0" />
        Key Terms to Know
      </Heading>
      <dl className="ec-glossary space-y-2.5">
        {terms.map(({ term, definition }) => (
          <div
            key={term}
            className="flex gap-3 bg-card border border-border rounded-2xl p-4 hover:border-primary/20 hover:shadow-sm transition-all duration-200"
          >
            <div className="w-1 rounded-full bg-gradient-to-b from-primary/70 to-primary/20 flex-shrink-0 self-stretch min-h-[2rem]" />
            <div className="flex-1 min-w-0">
              <dt className="text-sm font-bold text-foreground mb-1">{term}</dt>
              <dd className="text-sm text-muted-foreground leading-relaxed">{definition}</dd>
            </div>
          </div>
        ))}
      </dl>
    </section>
  );
}
