import { useState } from "react";
import { FlaskConical, ChevronDown } from "lucide-react";

interface FormulaBlockProps {
  title?: string;
  formula: string | string[];
  legend?: string;
  source: string;
  sourceHref?: string;
  collapsible?: boolean;
}

export default function FormulaBlock({
  title = "Mathematical Methodology",
  formula,
  legend,
  source,
  sourceHref,
  collapsible = false,
}: FormulaBlockProps) {
  const [open, setOpen] = useState(!collapsible);
  const formulas = Array.isArray(formula) ? formula : [formula];

  return (
    <div className="ec-formula bg-gradient-to-br from-indigo-50 to-blue-50/40 dark:from-indigo-950/30 dark:to-blue-950/20 border border-indigo-200/80 dark:border-indigo-800/50 rounded-2xl mb-6 overflow-hidden shadow-sm">
      <button
        type="button"
        onClick={() => collapsible && setOpen(o => !o)}
        className={`w-full flex items-center gap-2.5 px-5 py-4 text-left ${
          collapsible
            ? "hover:bg-indigo-100/50 dark:hover:bg-indigo-900/20 transition-colors cursor-pointer"
            : "cursor-default"
        }`}
        aria-expanded={collapsible ? open : undefined}
      >
        <div className="w-7 h-7 rounded-lg bg-indigo-100 dark:bg-indigo-900/60 flex items-center justify-center flex-shrink-0">
          <FlaskConical className="w-3.5 h-3.5 text-indigo-600 dark:text-indigo-400" />
        </div>
        <h3 className="text-sm font-bold text-indigo-700 dark:text-indigo-300 flex-1">
          {collapsible ? "How this was calculated" : title}
        </h3>
        {collapsible && (
          <ChevronDown
            className={`w-4 h-4 text-indigo-500 transition-transform duration-200 ${open ? "rotate-180" : ""}`}
          />
        )}
      </button>

      <div
        className={`grid transition-all duration-300 ease-out ${
          open ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
        }`}
      >
        <div className="overflow-hidden">
          <div className="px-5 pb-5">
            <div className="border-t border-indigo-200/60 dark:border-indigo-800/40 mb-4" />
            {!collapsible && (
              <p className="text-xs font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-widest mb-3">
                {title}
              </p>
            )}
            <div className="font-mono text-xs sm:text-sm text-foreground space-y-1.5 mb-3 bg-white/70 dark:bg-white/[0.04] rounded-xl p-4 border border-indigo-100 dark:border-indigo-900/60">
              {formulas.map((f, i) => (
                <p key={i} className="leading-relaxed">{f}</p>
              ))}
            </div>
            {legend && (
              <p className="text-xs text-muted-foreground mb-3 leading-relaxed">{legend}</p>
            )}
            <p className="text-xs text-muted-foreground flex items-center gap-1.5 flex-wrap">
              <span className="font-semibold text-indigo-600 dark:text-indigo-400">Source:</span>
              {sourceHref ? (
                <a
                  href={sourceHref}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-indigo-600 dark:text-indigo-400 hover:underline"
                >
                  {source}
                </a>
              ) : (
                <span className="font-medium text-foreground">{source}</span>
              )}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
